#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, Q;
        scanf("%d %d", &N, &Q);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int queries[Q];
        for (int i = 0; i < Q; i++) {
            scanf("%d", &queries[i]);
        }
        for (int i = 0; i < Q; i++) {
            int query = queries[i];
            if (query < N) {
                printf("%d ", A[query]);
            } else {
                int count = 0;
                for (int j = 0; j < query; j++) {
                    if (j < N && A[j] >= query - j) {
                        count++;
                    }
                }
                printf("%d ", count);
            }
        }
        printf("\n");
    }
    return 0;
}

