    const A = readline().split(' ').map(Number);
    const queries = readline().split(' ').map(Number);
    const result = [];
    for (let query of queries) {
        if (query < N) {
            result.push(A[query]);
        } else {
            let count = 0;
            for (let j = 0; j < query; j++) {
                if (j < N && A[j] >= query - j) {
                    count++;
                }
            }
            result.push(count);
        }
    }
    console.log(result.join(' '));
}

